### Gradual Migration API

```rust
/// Builder for gradual migration
pub struct MigrationBuilder {
    /// Features to enable
    features: HashSet<MigrationFeature>,
    /// Per-operation overrides
    overrides: HashMap<String, MigrationMode>,
}

#[derive(Debug, Clone, Copy, Hash, Eq, PartialEq)]
pub enum MigrationFeature {
    /// Enable RaptorQ for join operations
    JoinEncoding,
    /// Enable RaptorQ for race operations
    RaceEncoding,
    /// Enable distributed region encoding
    DistributedRegions,
    /// Enable symbol-based cancellation
    SymbolCancellation,
    /// Enable symbol-based tracing
    SymbolTracing,
    /// Enable epoch barriers
    EpochBarriers,
}

impl MigrationBuilder {
    /// Enable a specific migration feature
    pub fn enable(mut self, feature: MigrationFeature) -> Self {
        self.features.insert(feature);
        self
    }

    /// Disable a specific feature
    pub fn disable(mut self, feature: MigrationFeature) -> Self {
        self.features.remove(&feature);
        self
    }

    /// Enable all features (full RaptorQ mode)
    pub fn full_raptorq(mut self) -> Self {
        self.features = MigrationFeature::all().collect();
        self
    }

    /// Build the migration configuration
    pub fn build(self) -> MigrationConfig {
        MigrationConfig {
            features: self.features,
            overrides: self.overrides,
        }
    }
}

/// Use migration configuration
pub fn configure_migration() -> MigrationBuilder {
    MigrationBuilder::default()
}

// Example usage:
// let config = configure_migration()
//     .enable(MigrationFeature::JoinEncoding)
//     .enable(MigrationFeature::DistributedRegions)
//     .build();
```

### Legacy API Adapters

```rust
/// Adapter that presents traditional API over symbol-native implementation
pub mod legacy {
    use super::*;

    /// Traditional join that internally uses symbols
    pub async fn join_all<T, E, I, F, Fut>(futures: I) -> Vec<Result<T, E>>
    where
        T: Serialize + DeserializeOwned + Send + Sync,
        E: Serialize + DeserializeOwned + Send + Sync,
        I: IntoIterator<Item = F>,
        F: FnOnce() -> Fut,
        Fut: Future<Output = Result<T, E>>,
    {
        // Check migration config
        let config = current_migration_config();

        if config.is_enabled(MigrationFeature::JoinEncoding) {
            // Use symbol-native implementation, decode results
            let symbol_results = symbol_join_all(futures).await;
            symbol_results.into_iter()
                .map(|r| r.traditionalize())
                .collect()
        } else {
            // Use traditional implementation
            traditional_join_all(futures).await
        }
    }

    /// Traditional race that internally uses symbols
    pub async fn race_all<T, E, I, F, Fut>(futures: I) -> Result<T, Vec<E>>
    where
        T: Serialize + DeserializeOwned + Send,
        E: Serialize + DeserializeOwned + Send,
        I: IntoIterator<Item = F>,
        F: FnOnce() -> Fut,
        Fut: Future<Output = Result<T, E>>,
    {
        let config = current_migration_config();

        if config.is_enabled(MigrationFeature::RaceEncoding) {
            symbol_race_all(futures).await.traditionalize()
        } else {
            traditional_race_all(futures).await
        }
    }
}
