## E2E Tests

```rust
#[cfg(test)]
mod e2e {
    use super::*;
    use tracing_subscriber::fmt::format::FmtSpan;

    fn setup_logging() {
        tracing_subscriber::fmt()
            .with_span_events(FmtSpan::FULL)
            .with_env_filter("raptorq_migration=debug")
            .try_init()
            .ok();
    }

    #[tokio::test]
    async fn test_gradual_migration_join() {
        setup_logging();
        tracing::info\!("Testing gradual migration for join operations");

        // Start with traditional mode
        let config = configure_migration().build();
        assert\!(\!config.is_enabled(MigrationFeature::JoinEncoding));

        let results = with_config(config, || async {
            legacy::join_all(vec\![
                || async { Ok::<_, ()>(1) },
                || async { Ok::<_, ()>(2) },
            ]).await
        }).await;

        tracing::info\!(results = ?results, "Traditional mode results");
        assert_eq\!(results, vec\![Ok(1), Ok(2)]);

        // Enable RaptorQ for join
        let config = configure_migration()
            .enable(MigrationFeature::JoinEncoding)
            .build();

        let results = with_config(config, || async {
            legacy::join_all(vec\![
                || async { Ok::<_, ()>(3) },
                || async { Ok::<_, ()>(4) },
            ]).await
        }).await;

        tracing::info\!(results = ?results, "Symbol-native mode results");
        assert_eq\!(results, vec\![Ok(3), Ok(4)]);
    }

    #[tokio::test]
    async fn test_mixed_mode_operation() {
        setup_logging();
        tracing::info\!("Testing mixed mode operation");

        // Enable only some features
        let config = configure_migration()
            .enable(MigrationFeature::DistributedRegions)
            // JoinEncoding not enabled
            .build();

        // Create a region (uses RaptorQ)
        let region = with_config(config.clone(), || async {
            create_distributed_region().await
        }).await;
        tracing::info\!(region_id = ?region.id(), "Created distributed region");

        // Join within region (uses traditional, not RaptorQ)
        let results = with_config(config, || async {
            region.run(|cx| async move {
                legacy::join_all(vec\![
                    || async { Ok::<_, ()>(1) },
                    || async { Ok::<_, ()>(2) },
                ]).await
            }).await
        }).await;

        tracing::info\!(
            results = ?results,
            region_used_raptorq = true,
            join_used_raptorq = false,
            "Mixed mode operation complete"
        );
    }

    #[tokio::test]
    async fn test_migration_feature_toggle_at_runtime() {
        setup_logging();
        tracing::info\!("Testing runtime feature toggle");

        let config = Arc::new(RwLock::new(configure_migration().build()));

        // Run with initial config
        {
            let c = config.read().await.clone();
            tracing::info\!(features_enabled = ?c.enabled_features(), "Initial config");
        }

        // Toggle feature at runtime
        {
            let mut c = config.write().await;
            *c = configure_migration()
                .enable(MigrationFeature::JoinEncoding)
                .build();
            tracing::info\!(features_enabled = ?c.enabled_features(), "Updated config");
        }

        // Subsequent operations use new config
        let c = config.read().await.clone();
        assert\!(c.is_enabled(MigrationFeature::JoinEncoding));
    }

    #[tokio::test]
    async fn test_backward_compatible_api() {
        setup_logging();
        tracing::info\!("Testing backward compatible API surface");

        // This test verifies that existing code patterns work unchanged

        // Old API pattern: direct join_all
        let results: Vec<Result<i32, ()>> = futures::future::join_all(vec\![
            Box::pin(async { Ok(1) }) as Pin<Box<dyn Future<Output = _> + Send>>,
            Box::pin(async { Ok(2) }),
        ]).await;

        tracing::info\!(results = ?results, "Old API pattern works");

        // New API pattern with migration: legacy::join_all
        let config = configure_migration().full_raptorq().build();
        let results = with_config(config, || async {
            legacy::join_all(vec\![
                || async { Ok::<_, ()>(1) },
                || async { Ok::<_, ()>(2) },
            ]).await
        }).await;

        tracing::info\!(results = ?results, "New API with migration works");

        // Results are identical
        assert_eq\!(results, vec\![Ok(1), Ok(2)]);
    }
}
